/// Five-section ACR BI-RADS structured report from Gemma 4 or template fallback.
class ReportResult {
  String clinicalIndication;
  String findings;
  String biRadsAssessment;
  String impression;
  String recommendation;

  /// True if generated by on-device Gemma 4; false if from the template fallback.
  final bool isAiGenerated;

  ReportResult({
    required this.clinicalIndication,
    required this.findings,
    required this.biRadsAssessment,
    required this.impression,
    required this.recommendation,
    required this.isAiGenerated,
  });

  /// Returns a new instance with updated fields (used for in-app user edits).
  ReportResult copyWith({
    String? clinicalIndication,
    String? findings,
    String? biRadsAssessment,
    String? impression,
    String? recommendation,
  }) {
    return ReportResult(
      clinicalIndication: clinicalIndication ?? this.clinicalIndication,
      findings:           findings           ?? this.findings,
      biRadsAssessment:   biRadsAssessment   ?? this.biRadsAssessment,
      impression:         impression         ?? this.impression,
      recommendation:     recommendation     ?? this.recommendation,
      isAiGenerated:      isAiGenerated,
    );
  }
}
